class Solution:
    def smallestGoodBase(self, n: int) -> str:
        import math
        for len1 in range(int(math.log(n, 2))+2, 1, -1):
            k = int(n ** (1.0/len1))
            for cand in (k, k+1, k-1):
                if cand >= 2 and (pow(cand, len1) - 1) == (cand - 1) * n:
                    return str(cand)
        return str(n - 1)

